// src/RoutesApp.js
import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { useAuth } from "./context/AuthContext";

// Páginas (que já criamos em src/pages/…)
import LoginPage from "./pages/LoginPage";
import DashboardAluno from "./pages/DashboardAluno";
import DashboardRecepcao from "./pages/DashboardRecepcao";

// Componentes de lista/CRUD (stubs que criamos em src/components/…)
import ListaPeriodos from "./components/ListaPeriodos";
import ListaDisciplinas from "./components/ListaDisciplinas";
import ListaPacientes from "./components/ListaPacientes";
import ListaAlunos from "./components/ListaAlunos";
import ListaAgendamentos from "./components/ListaAgendamentos";
import FormAgendamento from "./components/FormAgendamento";

/**
 * Se o usuário não estiver logado (user == null), redireciona para /login.
 */
function ProtectedRoute({ children }) {
  const { user } = useAuth();
  if (!user) {
    return <Navigate to="/login" replace />;
  }
  return children;
}

export default function RoutesApp() {
  return (
    <BrowserRouter>
      <Routes>
        {/* Rota pública de login */}
        <Route path="/login" element={<LoginPage />} />

        {/* Rotas privadas */}
        <Route
          path="/"
          element={
            <ProtectedRoute>
              <DashboardRecepcao />
            </ProtectedRoute>
          }
        >
          {/* Subrotas que aparecem dentro de DashboardRecepcao */}
          <Route
            path="aluno"
            element={
              <ProtectedRoute>
                <DashboardAluno />
              </ProtectedRoute>
            }
          />
          <Route
            path="periodos"
            element={
              <ProtectedRoute>
                <ListaPeriodos />
              </ProtectedRoute>
            }
          />
          <Route
            path="disciplinas"
            element={
              <ProtectedRoute>
                <ListaDisciplinas />
              </ProtectedRoute>
            }
          />
          <Route
            path="pacientes"
            element={
              <ProtectedRoute>
                <ListaPacientes />
              </ProtectedRoute>
            }
          />
          <Route
            path="alunos"
            element={
              <ProtectedRoute>
                <ListaAlunos />
              </ProtectedRoute>
            }
          />
          <Route
            path="agendamentos"
            element={
              <ProtectedRoute>
                <ListaAgendamentos />
              </ProtectedRoute>
            }
          />
          <Route
            path="agendar"
            element={
              <ProtectedRoute>
                <FormAgendamento />
              </ProtectedRoute>
            }
          />
        </Route>

        {/* Qualquer outra rota cai aqui e redireciona para /login */}
        <Route path="*" element={<Navigate to="/login" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
